140	// DefaultRouteStatus is the resolver for the defaultRouteStatus field.
141	func (r *queryResolver) DefaultRouteStatus(ctx context.Context) (*DefaultRouteStatus, error) {
142		svc, err := agent.NewServiceFromWorkDir(r.WorkingDir)
143		if err != nil {
144			return nil, nil //nolint:nilerr
145		}
146		dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
147		if err != nil {
148			return &DefaultRouteStatus{}, nil //nolint:nilerr
149		}
150		result := &DefaultRouteStatus{ModelRef: dec.Model}
151		if dec.Provider != "" {
152			p := dec.Provider
153			result.ResolvedProvider = &p
154		}
155		if dec.Model != "" {
156			m := dec.Model
157			result.ResolvedModel = &m
158		}
159		return result, nil
160	}
