162	// ProviderTrend is the resolver for the providerTrend field.
163	// It aggregates the sessions index into time buckets for one provider/harness
164	// and computes a projected-run-out-in-hours callout from the last-24h slope.
165	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
166		name = strings.TrimSpace(name)
167		if name == "" {
168			return nil, fmt.Errorf("name required")
169		}
170		if windowDays != 7 && windowDays != 30 {
171			return nil, fmt.Errorf("windowDays must be 7 or 30")
172		}
173		now := time.Now().UTC()
174		entries := r.sessionIndexEntries()
175	
176		kind, detected := detectProviderOrHarness(ctx, r, name)
177		bucketKind := agent.MatchProvider
178		if kind == ProviderKindHarness {
179			bucketKind = agent.MatchHarness
180		}
181	
182		bucketSize := time.Hour
183		if windowDays > 7 {
184			bucketSize = 4 * time.Hour
185		}
186		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
187		series := make([]*ProviderTrendPoint, 0, len(buckets))
188		for _, b := range buckets {
189			series = append(series, &ProviderTrendPoint{
190				BucketStart: b.Start.UTC().Format(time.RFC3339),
191				Tokens:      b.Tokens,
192				Requests:    b.Requests,
193			})
194		}
195	
196		trend := &ProviderTrend{
197			Name:       name,
198			Kind:       kind,
199			WindowDays: windowDays,
200			Series:     series,
201		}
202	
203		if detected != nil {
204			if ceiling := detected.ceilingTokens; ceiling > 0 {
205				c := ceiling
206				trend.CeilingTokens = &c
207				remaining := detected.remaining
208				if remaining < 0 {
209					remaining = ceiling - sumTailTokens(buckets, 24)
210				}
211				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
212					trend.ProjectedRunOutHours = &p
213				}
214			}
215		}
216	
217		return trend, nil
218	}
