220	// --------- helpers ---------
221	
222	type detectedRow struct {
223		ceilingTokens int
224		remaining     int
225	}
226	
227	// detectProviderOrHarness looks up a name against providers first, then
228	// harnesses, returning the resolved kind and quota signal (if any).
229	func detectProviderOrHarness(ctx context.Context, r *queryResolver, name string) (ProviderKind, *detectedRow) {
230		if svc, err := agentlib.New(agentlib.ServiceOptions{}); err == nil {
231			harnesses, _ := svc.ListHarnesses(ctx)
232			for _, h := range harnesses {
233				if strings.EqualFold(h.Name, name) {
234					q := quotaFromHarnessInfo(h)
235					return ProviderKindHarness, detectedFromQuota(q)
236				}
237			}
238		}
239		if snapshots, ok, _ := agent.ConfiguredProviderSnapshots(r.WorkingDir); ok {
240			for _, p := range snapshots {
241				if strings.EqualFold(p.Name, name) {
242					q := quotaFromProviderInfo(p)
243					return ProviderKindEndpoint, detectedFromQuota(q)
244				}
245			}
246		}
247		if providers, err := liveProviderInfos(ctx, r.WorkingDir); err == nil {
248			for _, p := range providers {
249				if strings.EqualFold(p.Name, name) {
250					q := quotaFromProviderInfo(p)
251					return ProviderKindEndpoint, detectedFromQuota(q)
252				}
253			}
254		}
255		return ProviderKindEndpoint, nil
256	}
257	
258	func detectedFromQuota(q *ProviderQuota) *detectedRow {
259		if q == nil {
260			return nil
261		}
262		row := &detectedRow{ceilingTokens: -1, remaining: -1}
263		if q.CeilingTokens != nil {
264			row.ceilingTokens = *q.CeilingTokens
265		}
266		if q.Remaining != nil {
267			row.remaining = *q.Remaining
268		}
269		return row
270	}
