272	// projectRunOutHours returns the hours projected until current headroom is used
273	// based on the last-24-hour slope of the bucket series. Returns 0 when the
274	// slope is non-positive, headroom is gone/unknown, or the series is too
275	// short to estimate.
276	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
277		if len(buckets) < 2 {
278			return 0
279		}
280		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
281		// buckets; 1h buckets gives 24.
282		n := 24
283		if n > len(buckets) {
284			n = len(buckets)
285		}
286		tail := buckets[len(buckets)-n:]
287		tokens := make([]float64, len(tail))
288		for i, b := range tail {
289			tokens[i] = float64(b.Tokens)
290		}
291		perBucket := agent.LinearSlope(tokens)
292		// Convert slope-per-bucket to slope-per-hour.
293		var bucketHours float64
294		if len(tail) >= 2 {
295			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
296		}
297		if bucketHours <= 0 {
298			bucketHours = 1
299		}
300		perHour := perBucket / bucketHours
301		if perHour <= 0 {
302			return 0
303		}
304		if remaining <= 0 {
305			return 0
306		}
307		hours := remaining / perHour
308		if hours <= 0 {
309			return 0
310		}
311		return hours
312	}
313	
314	func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
315		if maxBuckets <= 0 || len(buckets) == 0 {
316			return 0
317		}
318		if maxBuckets > len(buckets) {
319			maxBuckets = len(buckets)
320		}
321		total := 0
322		for _, b := range buckets[len(buckets)-maxBuckets:] {
323			total += b.Tokens
324		}
325		return total
326	}
