328	func liveProviderInfos(ctx context.Context, workDir string) ([]agentlib.ProviderInfo, error) {
329		svc, err := agent.NewStatusProbeServiceFromWorkDir(workDir)
330		if err != nil {
331			return nil, err
332		}
333		return svc.ListProviders(ctx)
334	}
