336	func refreshProviderStatuses(workDir string) {
337		providerStatusCache.Lock()
338		if providerStatusCache.inFlight[workDir] {
339			providerStatusCache.Unlock()
340			return
341		}
342		providerStatusCache.inFlight[workDir] = true
343		providerStatusCache.Unlock()
344	
345		go func() {
346			defer func() {
347				providerStatusCache.Lock()
348				delete(providerStatusCache.inFlight, workDir)
349				providerStatusCache.Unlock()
350			}()
351			ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
352			defer cancel()
353			providers, err := liveProviderInfos(ctx, workDir)
354			if err != nil {
355				return
356			}
357			rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
358			storeProviderRows(workDir, rows)
359		}()
360	}
361	
362	func cachedProviderRows(workDir string) []*ProviderStatus {
363		providerStatusCache.Lock()
364		defer providerStatusCache.Unlock()
365		return cloneProviderRows(providerStatusCache.rows[workDir])
366	}
367	
368	func storeProviderRows(workDir string, rows []*ProviderStatus) {
369		providerStatusCache.Lock()
370		defer providerStatusCache.Unlock()
371		providerStatusCache.rows[workDir] = cloneProviderRows(rows)
372	}
