374	func providerStatusesFromInfos(providers []agentlib.ProviderInfo, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
375		lastChecked := now.UTC().Format(time.RFC3339)
376		results := make([]*ProviderStatus, 0, len(providers))
377		for _, p := range providers {
378			url := p.BaseURL
379			if url == "" {
380				url = "(api)"
381			}
382			ps := &ProviderStatus{
383				Name:              p.Name,
384				Kind:              ProviderKindEndpoint,
385				ProviderType:      p.Type,
386				BaseURL:           url,
387				Model:             p.DefaultModel,
388				Status:            p.Status,
389				Reachable:         providerReachable(p),
390				Detail:            providerDetail(p),
391				ModelCount:        p.ModelCount,
392				IsDefault:         p.IsDefault,
393				LastCheckedAt:     strPtr(lastChecked),
394				DefaultForProfile: defaultProfilesForEndpoint(p),
395			}
396			if ps.ProviderType == "" {
397				ps.ProviderType = "endpoint"
398			}
399			if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
400				s := p.CooldownState.Until.UTC().Format(time.RFC3339)
401				ps.CooldownUntil = &s
402			}
403			ps.Usage = buildUsage(entries, p.Name, agent.MatchProvider, now)
404			ps.Quota = quotaFromProviderInfo(p)
405			results = append(results, ps)
406		}
407		return results
408	}
