410	func providerRowsWithUsage(rows []*ProviderStatus, entries []agent.SessionIndexEntry, now time.Time) []*ProviderStatus {
411		out := cloneProviderRows(rows)
412		for _, row := range out {
413			row.Usage = buildUsage(entries, row.Name, agent.MatchProvider, now)
414		}
415		return out
416	}
