418	func cloneProviderRows(rows []*ProviderStatus) []*ProviderStatus {
419		if len(rows) == 0 {
420			return nil
421		}
422		out := make([]*ProviderStatus, 0, len(rows))
423		for _, row := range rows {
424			if row == nil {
425				continue
426			}
427			clone := *row
428			if row.DefaultForProfile != nil {
429				clone.DefaultForProfile = append([]string(nil), row.DefaultForProfile...)
430			}
431			out = append(out, &clone)
432		}
433		return out
434	}
