436	// sessionIndexEntries reads the project's session index for all available
437	// shards. Errors are swallowed — a missing index is a normal "no data" state.
438	func (r *queryResolver) sessionIndexEntries() []agent.SessionIndexEntry {
439		logDir := agent.SessionLogDirForWorkDir(r.WorkingDir)
440		if logDir == "" {
441			return nil
442		}
443		entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
444		if err != nil {
445			return nil
446		}
447		return entries
448	}
449	
450	func buildUsage(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) *ProviderUsage {
451		counts := agent.AggregateUsageCounts(entries, name, kind, now)
452		// FEAT-014 no-fabrication: when the session index has no rows attributable
453		// to this name, return nil so the UI renders "not reported" instead of
454		// fabricated "0 / 0" counts.
455		if counts.TokensLastHour == 0 && counts.TokensLast24h == 0 &&
456			counts.RequestsLastHour == 0 && counts.RequestsLast24h == 0 {
457			return nil
458		}
459		u := &ProviderUsage{}
460		v := counts.TokensLastHour
461		u.TokensUsedLastHour = &v
462		v2 := counts.TokensLast24h
463		u.TokensUsedLast24h = &v2
464		v3 := counts.RequestsLastHour
465		u.RequestsLastHour = &v3
466		v4 := counts.RequestsLast24h
467		u.RequestsLast24h = &v4
468		return u
469	}
