471	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
472	// Returns nil when no token-level ceiling is published.
473	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
474		if p.Quota == nil {
475			return nil
476		}
477		return quotaFromState(p.Quota)
478	}
479	
480	// quotaFromHarnessInfo derives a ProviderQuota from the upstream HarnessInfo.
481	// When a rate-limit signal has been captured for this harness (via
482	// RecordHarnessRateLimit — typically on the server's harness-dispatch path
483	// after parsing response headers with agent.ParseRateLimitHeaders), that
484	// signal takes precedence because it carries absolute token ceilings. The
485	// upstream HarnessInfo.Quota only exposes percent-used windows without an
486	// absolute ceiling. Returns nil when nothing usable is published.
487	func quotaFromHarnessInfo(info agentlib.HarnessInfo) *ProviderQuota {
488		if sig, ok := LookupHarnessRateLimit(info.Name); ok {
489			if q := QuotaFromRateLimitSignal(sig); q != nil {
490				return q
491			}
492		}
493		if info.Quota == nil {
494			return nil
495		}
496		return quotaFromState(info.Quota)
497	}
498	
499	// quotaFromState derives a ProviderQuota from an upstream QuotaState. The
500	// upstream QuotaWindow doesn't expose absolute token ceilings (only percent
501	// used), so we surface the window length and reset time only. Ceiling and
502	// remaining stay unknown unless a harness-specific rate-limit-header path
503	// populates them via QuotaFromRateLimitSignal.
504	func quotaFromState(state *agentlib.QuotaState) *ProviderQuota {
505		if state == nil || len(state.Windows) == 0 {
506			return nil
507		}
508		var windowSeconds int
509		var resetAt string
510		for _, w := range state.Windows {
511			if strings.EqualFold(w.LimitID, "extra") {
512				continue
513			}
514			if windowSeconds == 0 && w.WindowMinutes > 0 {
515				windowSeconds = w.WindowMinutes * 60
516			}
517			if resetAt == "" {
518				if w.ResetsAt != "" {
519					resetAt = w.ResetsAt
520				} else if w.ResetsAtUnix > 0 {
521					resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
522				}
523			}
524			if windowSeconds > 0 && resetAt != "" {
525				break
526			}
527		}
528		if windowSeconds == 0 && resetAt == "" {
529			return nil
530		}
531		q := &ProviderQuota{}
532		if windowSeconds > 0 {
533			v := windowSeconds
534			q.CeilingWindowSeconds = &v
535		}
536		if resetAt != "" {
537			v := resetAt
538			q.ResetAt = &v
539		}
540		return q
541	}
542	
543	// QuotaFromRateLimitSignal produces a ProviderQuota from a parsed rate-limit
544	// header signal (see agent.ParseRateLimitHeaders). Exposed for future call
545	// sites where the server captures harness response headers.
546	func QuotaFromRateLimitSignal(sig agent.RateLimitSignal) *ProviderQuota {
547		if !sig.HasAny() {
548			return nil
549		}
550		q := &ProviderQuota{}
551		if sig.CeilingTokens >= 0 {
552			v := sig.CeilingTokens
553			q.CeilingTokens = &v
554		}
555		if sig.CeilingWindowSeconds >= 0 {
556			v := sig.CeilingWindowSeconds
557			q.CeilingWindowSeconds = &v
558		}
559		if sig.Remaining >= 0 {
560			v := sig.Remaining
561			q.Remaining = &v
562		}
563		if !sig.ResetAt.IsZero() {
564			v := sig.ResetAt.UTC().Format(time.RFC3339)
565			q.ResetAt = &v
566		}
567		return q
568	}
569	
570	// defaultProfilesForEndpoint returns the profile names where this endpoint is
571	// a default candidate. Current service surface exposes only a single
572	// IsDefault flag, so we return ["default"] when set, [] otherwise. The return
573	// shape supports multi-profile expansion without breaking callers.
574	func defaultProfilesForEndpoint(p agentlib.ProviderInfo) []string {
575		if p.IsDefault {
576			return []string{"default"}
577		}
578		return []string{}
579	}
580	
581	func providerReachable(p agentlib.ProviderInfo) bool {
582		return strings.EqualFold(strings.TrimSpace(p.Status), "connected")
583	}
584	
585	func providerDetail(p agentlib.ProviderInfo) string {
586		if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
587			return p.LastError.Detail
588		}
589		for _, ep := range p.EndpointStatus {
590			if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
591				return ep.LastError.Detail
592			}
593			if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
594				return ep.Status
595			}
596		}
597		if strings.TrimSpace(p.Status) != "" {
598			if strings.EqualFold(p.Status, "unknown") {
599				return "not checked yet"
600			}
601			return p.Status
602		}
603		return "not reported"
604	}
605	
606	func harnessTypeLabel(info agentlib.HarnessInfo) string {
607		if info.Type != "" {
608			return info.Type
609		}
610		return "subprocess"
611	}
612	
613	func harnessStatusLine(info agentlib.HarnessInfo) string {
614		if info.Available {
615			return "available"
616		}
617		if info.Error != "" {
618			return "unavailable: " + info.Error
619		}
620		return "unavailable"
621	}
622	
623	func harnessDetail(info agentlib.HarnessInfo) string {
624		if info.LastError != nil && strings.TrimSpace(info.LastError.Detail) != "" {
625			return info.LastError.Detail
626		}
627		if strings.TrimSpace(info.Error) != "" {
628			return info.Error
629		}
630		if info.Available && strings.TrimSpace(info.Path) != "" {
631			return info.Path
632		}
633		if info.Available {
634			return "available"
635		}
636		return "binary not found"
637	}
