10	// TestGraphQLPerfMatrix_Baseline is the "measurement surface" the bead calls
11	// out: it seeds the default fixture, runs every Target, and — when
12	// DDX_BENCH_REPORT_DIR is set — writes the baseline report into that
13	// directory. This test is deliberately a `TestXxx` (not a `BenchmarkXxx`) so
14	// it runs under plain `go test` and anyone can reproduce the numbers with the
15	// same recipe CI will use.
16	//
17	// The acceptance criteria (ddx-9ce6842a AC §5) give per-target p95 budgets.
18	// This test asserts them for `bead(id:)` and `beadsByProject`; the cross-
19	// project `beads` target is logged but not gated, because it is the
20	// worst-case scan shape — a hard assertion here would tie the test to
21	// hardware. The markdown/JSON baseline preserves those numbers so a CI gate
22	// in a follow-up bead can diff against them.
23	func TestGraphQLPerfMatrix_Baseline(t *testing.T) {
24		if testing.Short() {
25			t.Skip("perf matrix skipped in -short mode")
26		}
27		spec := DefaultBeadFixtureSpec()
28		f := BuildBeadFixture(t, spec)
29		report := RunMatrix(t, f, DefaultIterations)
30	
31		for _, r := range report.Targets {
32			switch r.Name {
33			case "bead":
34				if r.InProcess.P95 > 50 {
35					t.Errorf("bead(id:) in-process p95=%.2fms > 50ms budget", r.InProcess.P95)
36				}
37				if r.HTTP != nil && r.HTTP.P95 > 200 {
38					t.Errorf("bead(id:) HTTP p95=%.2fms > 200ms budget", r.HTTP.P95)
39				}
40			case "beadsByProject":
41				if r.InProcess.P95 > 75 {
42					t.Errorf("beadsByProject in-process p95=%.2fms > 75ms budget", r.InProcess.P95)
43				}
44				if r.HTTP != nil && r.HTTP.P95 > 250 {
45					t.Errorf("beadsByProject HTTP p95=%.2fms > 250ms budget", r.HTTP.P95)
46				}
47			}
48			httpLine := "n/a"
49			if r.HTTP != nil {
50				httpLine = fmt.Sprintf("p50=%.2fms p95=%.2fms p99=%.2fms", r.HTTP.P50, r.HTTP.P95, r.HTTP.P99)
51			}
52			t.Logf("target=%s iter=%d in-proc(p50=%.2fms p95=%.2fms p99=%.2fms) http(%s)",
53				r.Name, r.Iterations,
54				r.InProcess.P50, r.InProcess.P95, r.InProcess.P99,
55				httpLine,
56			)
57		}
58	
59		// Optional report writing — keeps CI quick by default, lets humans
60		// regenerate the baseline with `DDX_BENCH_REPORT_DIR=... go test ...`.
61		if dir := os.Getenv("DDX_BENCH_REPORT_DIR"); dir != "" {
62			date := os.Getenv("DDX_BENCH_REPORT_DATE")
63			if date == "" {
64				date = time.Now().UTC().Format("2006-01-02")
65			}
66			md, js, err := WriteReports(dir, date, report)
67			if err != nil {
68				t.Fatalf("write reports: %v", err)
69			}
70			t.Logf("wrote baseline report: %s (+ %s)", md, js)
71		}
72	}
