74	// BenchmarkGraphQLPerfMatrix is the `go test -bench` entry point. Each
75	// iteration runs the whole matrix so benchstat can diff runs.
76	func BenchmarkGraphQLPerfMatrix(b *testing.B) {
77		spec := DefaultBeadFixtureSpec()
78		f := BuildBeadFixture(b, spec)
79	
80		b.ResetTimer()
81		for i := 0; i < b.N; i++ {
82			_ = RunMatrix(b, f, DefaultIterations)
83		}
84	}
