1	package perf
2	
3	import (
4		"bytes"
5		"encoding/json"
6		"fmt"
7		"net/http"
8		"net/http/httptest"
9		"sort"
10		"testing"
11		"time"
12	)
13	
14	// Target is one entry in the benchmark matrix. Adding a new GraphQL query
15	// shape is a single-entry change: append a Target to Targets() with an
16	// in-process call and a GraphQL query string. Both are exercised on every
17	// harness run (ddx-9ce6842a AC §1).
18	type Target struct {
19		Name       string
20		Query      string
21		InProcess  func(f *BeadFixture) error
22		SkipInHTTP bool
23	}
24	
25	// Result holds timings and metadata for one Target over one fixture.
26	type Result struct {
27		Name       string       `json:"name"`
28		Iterations int          `json:"iterations"`
29		InProcess  Percentiles  `json:"in_process_ms"`
30		HTTP       *Percentiles `json:"http_ms,omitempty"`
31	}
32	
33	// Percentiles holds p50/p95/p99 in floating-point milliseconds.
34	type Percentiles struct {
35		P50 float64 `json:"p50"`
36		P95 float64 `json:"p95"`
37		P99 float64 `json:"p99"`
38	}
39	
40	// MatrixReport is the full output of one RunMatrix call — a list of per-target
41	// results plus fixture/environment metadata. It is what baseline reports
42	// compare against and what CI will diff in a follow-up bead.
43	type MatrixReport struct {
44		GeneratedAt string    `json:"generated_at"`
45		Environment string    `json:"environment"`
46		Fixture     FixtureID `json:"fixture"`
47		Targets     []Result  `json:"targets"`
48	}
49	
50	// FixtureID is the fixture-shape metadata stamped into every report so a
51	// regression check can sanity-check that it's comparing apples to apples.
52	type FixtureID struct {
53		Projects                int `json:"projects"`
54		BeadsPerProject         int `json:"beads_per_project"`
55		TotalBeads              int `json:"total_beads"`
56		AgentSessionsPerProject int `json:"agent_sessions_per_project"`
57	}
58	
59	// DefaultIterations is the sample size used when a run request does not
60	// override it. Chosen so p95/p99 are defensible on a 5,000-bead fixture
61	// without extending benchmark wall time past a few seconds.
62	const DefaultIterations = 40
63	
64	// Targets returns the harness matrix covering the five query shapes named in
65	// ddx-9ce6842a AC §1: bead(id:), beadsByProject, beads (cross-project),
66	// docGraph, agentSessions. Adding a new target is a single append here.
67	func Targets() []Target {
68		return []Target{
69			{
70				Name:  "bead",
71				Query: `query Q($id: ID!) { bead(id: $id) { id title status updatedAt } }`,
72				InProcess: func(f *BeadFixture) error {
73					snap, ok := f.Server.State().GetBeadSnapshot(f.TargetBeadID)
74					if !ok {
75						return fmt.Errorf("bead not found: %s", f.TargetBeadID)
76					}
77					if snap.ID != f.TargetBeadID {
78						return fmt.Errorf("unexpected bead id: %s", snap.ID)
79					}
80					return nil
81				},
82			},
83			{
84				Name:  "beadsByProject",
85				Query: `query Q($project: String!, $first: Int!) { beadsByProject(projectID: $project, first: $first) { totalCount edges { node { id title status } } } }`,
86				InProcess: func(f *BeadFixture) error {
87					snaps := f.Server.State().GetBeadSnapshotsForProject(f.TargetProject.ID, "", "", "")
88					if len(snaps) == 0 {
89						return fmt.Errorf("no snapshots for project %s", f.TargetProject.ID)
90					}
91					return nil
92				},
93			},
94			{
95				Name:  "beadsByProject_statusOpen",
96				Query: `query Q($project: String!, $first: Int!) { beadsByProject(projectID: $project, first: $first, status: "open") { totalCount edges { node { id } } } }`,
97				InProcess: func(f *BeadFixture) error {
98					snaps := f.Server.State().GetBeadSnapshotsForProject(f.TargetProject.ID, "open", "", "")
99					if len(snaps) == 0 {
100						return fmt.Errorf("no open snapshots for project %s", f.TargetProject.ID)
101					}
102					return nil
103				},
104			},
105			{
106				Name:  "beads_crossProject",
107				Query: `query Q($first: Int!) { beads(first: $first) { totalCount edges { node { id title status } } } }`,
108				InProcess: func(f *BeadFixture) error {
109					snaps := f.Server.State().GetBeadSnapshots("", "", "", "")
110					if len(snaps) != f.TotalBeads() {
111						return fmt.Errorf("cross-project snapshots: want %d, got %d", f.TotalBeads(), len(snaps))
112					}
113					return nil
114				},
115			},
116			{
117				Name:  "docGraph",
118				Query: `{ docGraph { rootDir documents { id path title } } }`,
119				InProcess: func(f *BeadFixture) error {
120					// The docGraph resolver is the in-process call — there is no
121					// cheaper "direct state" equivalent for it, so we exercise
122					// the HTTP path twice (once here via the handler, once in
123					// the HTTP measurement below). The second invocation still
124					// reports the distribution we care about.
125					resp, err := postGraphQL(f.Handler, `{ docGraph { rootDir documents { id path title } } }`, nil)
126					if err != nil {
127						return err
128					}
129					if len(resp.Errors) > 0 {
130						return fmt.Errorf("docGraph errors: %+v", resp.Errors)
131					}
132					return nil
133				},
134			},
135			{
136				Name:  "agentSessions",
137				Query: `{ agentSessions(first: 50) { totalCount edges { node { id harness model } } } }`,
138				InProcess: func(f *BeadFixture) error {
139					sessions := f.Server.State().GetAgentSessionsGraphQL(nil, nil)
140					_ = sessions // may be empty when fixture seeds 0 sessions; still exercised
141					return nil
142				},
143			},
144		}
145	}
146	
147	// RunMatrix executes every Target `iterations` times, once via the in-process
148	// call and once via the HTTP handler, and returns the combined report. If
149	// iterations ≤ 0 the harness uses DefaultIterations.
150	func RunMatrix(tb testing.TB, f *BeadFixture, iterations int) MatrixReport {
151		tb.Helper()
152		if iterations <= 0 {
153			iterations = DefaultIterations
154		}
155		targets := Targets()
156	
157		// Warm once per target so the first sample doesn't carry cold-cache cost
158		// (bead-location index, os page cache). The p50/p95/p99 we report reflect
159		// steady-state behaviour, which is what users feel on repeat navigations.
160		for _, t := range targets {
161			if t.InProcess != nil {
162				_ = t.InProcess(f)
163			}
164			if !t.SkipInHTTP && t.Query != "" {
165				_, _ = postGraphQL(f.Handler, t.Query, variablesFor(t, f))
166			}
167		}
168	
169		results := make([]Result, 0, len(targets))
170		for _, t := range targets {
171			r := Result{Name: t.Name, Iterations: iterations}
172			if t.InProcess != nil {
173				samples := make([]time.Duration, 0, iterations)
174				for i := 0; i < iterations; i++ {
175					start := time.Now()
176					if err := t.InProcess(f); err != nil {
177						tb.Fatalf("perf: target %s in-process failed: %v", t.Name, err)
178					}
179					samples = append(samples, time.Since(start))
180				}
181				r.InProcess = percentileMillis(samples)
182			}
183			if !t.SkipInHTTP && t.Query != "" {
184				samples := make([]time.Duration, 0, iterations)
185				vars := variablesFor(t, f)
186				for i := 0; i < iterations; i++ {
187					start := time.Now()
188					resp, err := postGraphQL(f.Handler, t.Query, vars)
189					elapsed := time.Since(start)
190					if err != nil {
191						tb.Fatalf("perf: target %s HTTP failed: %v", t.Name, err)
192					}
193					if len(resp.Errors) > 0 {
194						tb.Fatalf("perf: target %s graphql errors: %+v", t.Name, resp.Errors)
195					}
196					samples = append(samples, elapsed)
197				}
198				p := percentileMillis(samples)
199				r.HTTP = &p
200			}
201			results = append(results, r)
202		}
203	
204		return MatrixReport{
