230	type graphQLResponse struct {
231		Data   json.RawMessage  `json:"data"`
232		Errors []map[string]any `json:"errors,omitempty"`
233	}
234	
235	// postGraphQL submits one GraphQL query through the HTTP handler and returns
236	// the decoded response. It is the single HTTP entry point used by both the
237	// harness and the smoke tests so they share transport timings.
238	func postGraphQL(h http.Handler, query string, variables map[string]any) (graphQLResponse, error) {
239		payload := map[string]any{"query": query}
240		if variables != nil {
241			payload["variables"] = variables
242		}
243		raw, err := json.Marshal(payload)
244		if err != nil {
245			return graphQLResponse{}, fmt.Errorf("marshal: %w", err)
246		}
247		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(raw))
248		req.Header.Set("Content-Type", "application/json")
249		req.RemoteAddr = "127.0.0.1:12345"
250		w := httptest.NewRecorder()
251		h.ServeHTTP(w, req)
252		if w.Code != http.StatusOK {
253			return graphQLResponse{}, fmt.Errorf("status %d: %s", w.Code, w.Body.String())
254		}
255		var resp graphQLResponse
256		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
257			return graphQLResponse{}, fmt.Errorf("decode: %w body=%s", err, w.Body.String())
258		}
259		return resp, nil
260	}
261	
262	// PostGraphQL is the exported counterpart used by smoke tests in other
263	// packages that want to reuse the harness's HTTP entry point.
264	func PostGraphQL(h http.Handler, query string, variables map[string]any) error {
265		resp, err := postGraphQL(h, query, variables)
266		if err != nil {
267			return err
268		}
269		if len(resp.Errors) > 0 {
270			return fmt.Errorf("graphql errors: %+v", resp.Errors)
271		}
272		return nil
273	}
