275	func percentileMillis(samples []time.Duration) Percentiles {
276		if len(samples) == 0 {
277			return Percentiles{}
278		}
279		sort.Slice(samples, func(i, j int) bool { return samples[i] < samples[j] })
280		return Percentiles{
281			P50: toMillis(percentile(samples, 50)),
282			P95: toMillis(percentile(samples, 95)),
283			P99: toMillis(percentile(samples, 99)),
284		}
285	}
286	
287	func percentile(sorted []time.Duration, pct int) time.Duration {
288		if len(sorted) == 0 {
289			return 0
290		}
291		idx := (len(sorted)*pct + 99) / 100
292		if idx < 1 {
293			idx = 1
294		}
295		if idx > len(sorted) {
296			idx = len(sorted)
297		}
298		return sorted[idx-1]
299	}
300	
301	func toMillis(d time.Duration) float64 {
302		return float64(d.Microseconds()) / 1000.0
303	}
